-- create a stored procedure to delete inactive users
DELIMITER //
CREATE PROCEDURE delete_inactive_users()
BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE user_id INT;
    DECLARE cur CURSOR FOR SELECT user_id FROM users WHERE status = 'Inactive';
    DECLARE CONTINUE HANDLER FOUNDSET SET done = 1;

    OPEN cur;
    read_loop: LOOP
        FETCH cur INTO user_id;
        IF done THEN
            LEAVE read_loop;
        END IF;
        BEGIN
            -- delete record from users table
            DELETE FROM users WHERE user_id = user_id;
            -- log the status change
            INSERT INTO status_log (user_id, status, modification_date)
            VALUES (user_id, 'Active', CURRENT_TIMESTAMP);
        END;
    END LOOP;
    CLOSE cur;
END //
